:"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"160px","bottom":"51px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}},"background":{"desktop":{"value":{"color":"#000432","gradient":{"stops":[{"color":"#0f1419","position":0},{"color":"#000432","position":40},{"color":"#000864","position":100}],"direction":"135deg","enabled":true}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:linear-gradient(135deg,#0f1419 0%,#000432 40%,#000864 100%) !important}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"800px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}}}}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-nav-row\\">\\n  <a href=\\"/blog/\\" class=\\"blog-fc-back\\">\\n    <svg viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke-width=\\"2\\" aria-hidden=\\"true\\"><path d=\\"M19 12H5M12 19l-7-7 7-7\\"/></svg>\\n    Back to Insights\\n  </a>\\n  <span class=\\"blog-fc-badge\\">PRODUCTION PLANNING</span>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Nav: Back Link + Badge"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h1>Feature Codes: How to Turn 27 SKUs Into 1 Product</h1>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#ffffff","size":"42px","weight":"700","family":"Noto Sans","lineHeight":"1.2"}},"tablet":{"value":{"color":"#ffffff","size":"42px","weight":"700","family":"Noto Sans","lineHeight":"1.2"}},"phone":{"value":{"color":"#ffffff","size":"42px","weight":"700","family":"Noto Sans","lineHeight":"1.2"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog Title"}}}},"css":{"desktop":{"value":{"freeForm":"selector .et_pb_text_inner h1 { color: #fff !important; font-size: clamp(28px, 4.5vw, 42px) !important; font-weight: 700 !important; line-height: 1.2 !important; }"}},"tablet":{"value":{"freeForm":"selector .et_pb_text_inner h1 { color: #fff !important; font-size: clamp(28px, 4.5vw, 42px) !important; font-weight: 700 !important; line-height: 1.2 !important; }"}},"phone":{"value":{"freeForm":"selector .et_pb_text_inner h1 { color: #fff !important; font-size: clamp(28px, 4.5vw, 42px) !important; font-weight: 700 !important; line-height: 1.2 !important; }"}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>7 min read <span class=\\"blog-fc-meta-sep\\">&middot;</span> February 2026</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"rgba(255,255,255,0.85)","size":"15px","weight":"400","family":"Noto Sans"}},"tablet":{"value":{"color":"rgba(255,255,255,0.85)","size":"15px","weight":"400","family":"Noto Sans"}},"phone":{"value":{"color":"rgba(255,255,255,0.85)","size":"15px","weight":"400","family":"Noto Sans"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Meta: Read Time + Date"}}}},"css":{"desktop":{"value":{"freeForm":"selector .et_pb_text_inner p { color: rgba(255,255,255,0.85) !important; font-size: 15px !important; }"}},"tablet":{"value":{"freeForm":"selector .et_pb_text_inner p { color: rgba(255,255,255,0.85) !important; font-size: 15px !important; }"}},"phone":{"value":{"freeForm":"selector .et_pb_text_inner p { color: rgba(255,255,255,0.85) !important; font-size: 15px !important; }"}}}} /-->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-super-d\\" aria-hidden=\\"true\\"></div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Deco: Super D"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC Content"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"64px","bottom":"80px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening Paragraphs"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Your factory makes a shirt. Three sizes (S, M, L), three colors (red, blue, white), three collar types (V-neck, round, crew). That is 27 separate item codes. Each needs its own Bill of Materials, its own inventory tracking record, its own purchasing rules, its own reorder point. Scale this across a product line of even moderate complexity, and you suddenly have thousands of SKUs managing what is fundamentally the same product with minor variations.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening: SKU multiplication problem"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>This is not a theoretical problem. It is a pattern that repeats across every manufacturing sector that deals with configurable products. Electronics (brand/version/source), apparel (size/color/fabric), solar panels (electrical properties), machinery (dimensions/capacity). The result is an ERP system choked with nearly identical item masters, a warehouse team managing dozens of picking locations for functionally identical products, and a purchasing department juggling hundreds of reorder points that should be consolidated under a single material plan.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Opening: Cross-industry pattern"}}}}} /-->\n<!-- wp:divi/divider {"divider":{"advanced":{"line":{"desktop":{"value":{"show":"on","color":"#000864","style":"solid","position":"center","weight":"3px"}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Accent Divider"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"48px"}}},"spacing":{"desktop":{"value":{"margin":{"top":"40px","bottom":"40px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem with SKU Multiplication"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"SKU Problem Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>The Problem with SKU Multiplication</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: The Problem with SKU Multiplication"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>When you treat each product variation as a separate item code, several predictable problems emerge. First, <strong>inventory accuracy collapses</strong>. Your system shows zero stock of \\"medium blue V-neck,\\" so production stops waiting for replenishment. Meanwhile, the warehouse has excess inventory of \\"medium blue round-neck\\" sitting unused. The materials are identical. The manufacturing process is identical. But because they are tracked as separate items, the system cannot recognize they are interchangeable for material planning purposes.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory accuracy collapse"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Second, <strong>purchasing becomes exponentially more complex</strong>. Instead of one reorder point for \\"shirt fabric - blue,\\" you now have nine — one for each combination that uses blue fabric. Each variation triggers its own purchase requisition. Each has its own minimum order quantity, lead time buffer, and safety stock calculation. The purchasing team spends more time managing item-level parameters than actually negotiating with suppliers or optimizing order quantities.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Purchasing complexity"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Third, <strong>BOM maintenance becomes a nightmare</strong>. Your supplier changes the thread specification. Now you need to update 27 separate BOMs instead of one. A quality issue requires a material substitution. Again, 27 BOMs. A cost change needs to propagate through the system. 27 records. Every change multiplies across every SKU, and every manual update is an opportunity for error — which means some item codes will inevitably drift out of sync with reality.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: BOM maintenance nightmare"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Fourth, <strong>warehouse operations suffer</strong>. Picking errors increase because visually similar items are stored across different locations. Cycle counts take longer because each SKU requires separate verification. Space utilization drops because you cannot consolidate storage — the system treats each variation as a unique item requiring its own bin location.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Warehouse operations suffer"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The goal isn\'t fewer products. It\'s fewer item codes managing more products.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"tablet":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"phone":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Quote: Fewer item codes"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px","top":"32px"}}}}}},"css":{"desktop":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"tablet":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"phone":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"What Feature Codes Do"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Feature Codes Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>What Feature Codes Do</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: What Feature Codes Do"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><a href=\\"/products/erp/\\">DigiWin\'s ERP</a> feature code system solves this by separating the concept of a <strong>product</strong> from the concept of a <strong>variant</strong>. Instead of creating 27 separate item codes, you create one item master with multiple feature dimensions. The system defines the product once — its base BOM, its routing, its cost structure, its purchasing rules — and then layers variant dimensions on top.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Product vs variant concept"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>In the shirt example, you would define:</p><ul><li><strong>Feature 1 (Size):</strong> S, M, L</li><li><strong>Feature 2 (Color):</strong> Red, Blue, White</li><li><strong>Feature 3 (Collar):</strong> V-neck, Round, Crew</li></ul>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"List: Feature dimensions"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The system treats each combination as a unique variant for inventory tracking, order fulfillment, and warehouse management. When a customer orders \\"medium blue V-neck,\\" the system knows exactly which physical inventory to pick. But for BOM maintenance, purchasing planning, and cost accounting, all 27 variants roll up to a single item master. When you need to update the thread specification, you update one BOM — and it applies to all variants automatically.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Variant tracking explanation"}}}}} /-->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-data-card\\">\\n  <div class=\\"blog-fc-data-inline\\">\\n    <div><div class=\\"blog-fc-data-number\\">27 SKUs</div></div>\\n    <div class=\\"blog-fc-data-arrow\\">&rarr;</div>\\n    <div><div class=\\"blog-fc-data-number\\">1 Item Code</div></div>\\n  </div>\\n  <div class=\\"blog-fc-data-label\\">90%+ reduction in item master complexity</div>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Data Card: 27 SKUs → 1 Item Code"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>This is not just a data organization trick. It fundamentally changes how the system handles material planning. When you run MRP, the system aggregates demand across all feature combinations. If you have orders for 100 red shirts (across all sizes and collars) and 50 blue shirts (across all sizes and collars), MRP calculates fabric requirements at the color level — not at the individual SKU level. The result is consolidated purchase requisitions, more accurate reorder points, and fewer stockouts caused by artificial fragmentation of demand.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: MRP aggregation benefit"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Product vs Inventory Features"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Features Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Product Features vs Inventory Features</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: Product Features vs Inventory Features"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>DigiWin\'s feature code architecture includes a critical distinction: <strong>product features</strong> (attributes of the product itself) versus <strong>inventory features</strong> (attributes of how you track it). This separation unlocks capabilities that most ERP systems cannot support.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Feature distinction intro"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Product features are inherent to what you are making. Size, color, electrical rating, material grade — these are choices your customer makes when placing an order, and they often affect the BOM or routing. Inventory features, by contrast, are internal tracking dimensions that the customer never sees. Supplier brand (when multiple suppliers provide functionally identical components), customer-dedicated stock (when a large customer requires segregated inventory), lot number (for traceability without creating separate item codes), warehouse location (when the same product is stocked in multiple facilities) — these are all inventory features.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Product vs inventory features"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The power of this separation is that you can add inventory tracking complexity without exploding your item master. Consider a scenario: you manufacture solar panels, and you source the same photovoltaic cell from three different suppliers. The cells are functionally identical, but you need to track which supplier\'s material went into each finished panel for warranty traceability.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Solar panel example"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>In a traditional ERP, you would be forced to create three separate item codes for the same cell — one per supplier — and then three separate BOMs for the solar panel. With inventory features, you define one item code for the cell and add \\"supplier brand\\" as an inventory feature. The BOM references a single component. During production, the system tracks which supplier\'s inventory was issued — providing full traceability without fragmenting the item master.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory feature solution"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Real-World Applications"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Applications Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Real-World Applications Across Industries</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: Real-World Applications"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Electronics Manufacturing:</strong> A factory produces power adapters in multiple voltage ratings (12V, 24V, 48V), multiple connector types (USB-C, barrel jack, terminal block), and sources components from multiple suppliers. Without feature codes, this requires dozens of item codes. With feature codes, one item master with three product features and one inventory feature. BOM maintenance effort drops by 80%.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Electronics example"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Apparel and Textiles:</strong> A garment manufacturer produces workwear in 5 sizes, 6 colors, and 3 fabric weights. Traditional approach: 90 SKUs. Feature code approach: 1 item code with 3 product features. When a fabric supplier changes, one BOM update instead of 90.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Apparel example"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Industrial Components:</strong> A machining shop makes steel brackets in 8 lengths and 4 hole-pattern configurations. Each bracket can be supplied in raw steel or zinc-plated. Traditional approach: 64 SKUs. Feature code approach: 1 item code with 3 features.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Industrial components example"}}}}} /-->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-highlight\\">\\n  <p><strong>Feature-aware costing:</strong> DigiWin\'s feature code system supports cost differentiation at the feature level. If zinc-plated brackets cost more than raw steel (due to the plating process), you can assign incremental cost to the \\"plating\\" feature value without creating separate item codes. The system calculates the final product cost by summing the base item cost plus feature-specific cost adders — giving you variant-level cost accuracy without variant-level item master complexity.</p>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Highlight: Feature-Aware Costing"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Real Impact"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Impact Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>The Real Impact</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: The Real Impact"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>The benefits of feature codes extend far beyond reducing the number of rows in your item master table. The operational impacts touch nearly every function in a manufacturing organization.</p><p><strong>Product setup speed increases dramatically.</strong> Launching a new product with multiple variants no longer requires creating dozens of item codes, BOMs, and routing records. You define one item master, specify feature dimensions, and the system generates all valid combinations automatically.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Product setup speed"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>BOM maintenance errors drop.</strong> When a material specification changes, you update one BOM instead of dozens. Fewer update points means fewer opportunities for data entry errors and fewer instances where some SKUs drift out of sync with others.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: BOM error reduction"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Inventory visibility improves.</strong> Instead of seeing fragmented stock across dozens of SKUs, planners see consolidated inventory at the feature level. If total blue fabric inventory is sufficient but distributed across multiple combinations, the system recognizes that and avoids unnecessary purchase orders.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Inventory visibility"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Purchasing becomes simpler and more effective.</strong> MRP generates consolidated demand for materials common across feature combinations. Purchase requisitions aggregate by supplier and material, not by individual SKU — increasing order quantities, reducing administrative overhead, and improving supplier relationships.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Purchasing simplification"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p><strong>Warehouse operations become more efficient.</strong> Cycle counting is faster because feature-coded items can be counted at the aggregate level. Picking accuracy improves because visually similar items are no longer scattered across dozens of bin locations. Storage consolidation becomes possible.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Warehouse efficiency"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Feature codes don\'t just reduce SKU count. They restructure how the entire system thinks about product complexity — from planning to purchasing to production to warehouse management.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"tablet":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}},"phone":{"value":{"color":"#555555","size":"16px","weight":"500","family":"Noto Sans","lineHeight":"1.7"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Quote: System restructuring"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px","top":"32px"}}}}}},"css":{"desktop":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"tablet":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}},"phone":{"value":{"freeForm":"selector { border-left: 4px solid #00AFF0; background: #f8fafc; border-radius: 0 8px 8px 0; padding: 16px 24px; } selector .et_pb_text_inner p { font-style: italic; margin-bottom: 0 !important; }"}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"What This Means for Your Factory"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"760px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Factory Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}},"tablet":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}},"phone":{"value":{"padding":{"top":"0px","bottom":"0px","left":"16px","right":"16px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>What This Means for Your Factory</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"H2: What This Means for Your Factory"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>If your factory produces configurable products — anything with size, color, voltage, dimension, or material variations — you are almost certainly managing more SKUs than necessary. The question is not whether feature codes would help. The question is how much operational overhead you are currently tolerating because your ERP lacks this capability.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Diagnostic intro"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>Here is a straightforward diagnostic: count how many item codes in your system share 90%+ identical BOMs, differing only in a single component or dimension. If that number is in the dozens, you have SKU multiplication. If it is in the hundreds, you have SKU explosion. And if your team is maintaining separate spreadsheets to track which items are \\"really the same product,\\" you have already built a feature code system manually — you just do not have software support for it.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: Diagnostic questions"}}}}} /-->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<p>DigiWin\'s T100 ERP supports feature codes as a core architectural capability, not an add-on module. This means the entire system — from sales order entry to production planning to inventory management to costing — understands and respects feature-level logic. You are not working around the system. You are working with it.</p>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"tablet":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}},"phone":{"value":{"color":"#333333","size":"18px","weight":"400","family":"Noto Sans","lineHeight":"1.8"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Body: T100 positioning"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC FAQ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"60px","bottom":"60px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}},"background":{"desktop":{"value":{"color":"#f8fafc"}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"800px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Frequently Asked Questions</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"28px","weight":"700","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Heading"}}},"decoration":{"spacing":{"desktop":{"value":{"margin":{"bottom":"32px"}}}}}}} /-->\n<!-- wp:divi/accordion {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ Accordion"}}}},"title":{"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","size":"17px","color":"#000864"}}}}}},"content":{"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"400","size":"15px","lineHeight":"1.7em","color":"#333333"}}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"What are feature codes in ERP?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Feature codes are a product configuration system built into DigiWin\'s ERP that separates the concept of a product from the concept of a variant. Instead of creating a separate item code for every combination of size, color, material, or specification, you define one item master with multiple feature dimensions. The system manages the base BOM, routing, cost structure, and purchasing rules once, then layers variant dimensions on top — drastically reducing item master complexity while preserving full inventory tracking at the variant level.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"advanced":{"open":{"desktop":{"value":"on"}}},"meta":{"adminLabel":{"desktop":{"value":"FAQ: What are feature codes?"}}}}} /-->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"How do feature codes reduce SKU count?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Feature codes eliminate SKU multiplication by managing product variations as dimensions of a single item rather than separate item codes. For example, a product with 3 sizes, 3 colors, and 3 collar types would traditionally require 27 separate SKUs, each with its own BOM, inventory record, and purchasing rules. With feature codes, this becomes 1 item code with 3 feature dimensions. BOM maintenance effort drops dramatically — when a material specification changes, you update one BOM instead of 27. MRP also aggregates demand across all feature combinations, producing consolidated purchase requisitions instead of fragmented ones.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: How reduce SKU count?"}}}}} /-->\n<!-- wp:divi/accordion-item {"title":{"innerContent":{"desktop":{"value":"What is the difference between product features and inventory features?"}}},"content":{"innerContent":{"desktop":{"value":"<p>Product features are attributes inherent to what you are making — size, color, electrical rating, material grade — that your customer selects when placing an order and that may affect the BOM or routing. Inventory features are internal tracking dimensions the customer never sees, such as supplier brand (when multiple suppliers provide identical components), customer-dedicated stock, lot numbers for traceability, or warehouse location. This separation lets you add inventory tracking complexity for traceability and compliance without exploding your item master or creating duplicate BOMs.</p>"}}},"builderVersion":"5.0.0-public-beta.8","module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: Product vs inventory features?"}}}}} /-->\n<!-- /wp:divi/accordion -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC Related"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"80px","bottom":"80px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}},"background":{"desktop":{"value":{"color":"#F5F7FA"}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"1200px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Column"}}},"decoration":{"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"24px","right":"24px"}}}}}}} -->\n<!-- wp:divi/text {"content":{"innerContent":{"desktop":{"value":"<h2>Related Articles</h2>"}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"color":"#000864","size":"32px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"tablet":{"value":{"color":"#000864","size":"32px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}},"phone":{"value":{"color":"#000864","size":"32px","weight":"600","family":"Noto Sans","lineHeight":"1.3"}}}}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Heading"}}}}} /-->\n<!-- wp:divi/blog {"fullwidth":{"advanced":{"enable":{"desktop":{"value":"off"}}}},"readMore":{"advanced":{"enable":{"desktop":{"value":"on"}}},"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","color":"#00AFF0"}}}}}},"meta":{"advanced":{"showAuthor":{"desktop":{"value":"off"}}},"decoration":{"font":{"font":{"desktop":{"value":{"color":"#666666","family":"Noto Sans","weight":"400"}}}}}},"title":{"decoration":{"font":{"font":{"desktop":{"value":{"size":"18px","lineHeight":"1.4em","family":"Noto Sans","weight":"600","color":"#000864"}},"tablet":{"value":{"size":"16px"}},"phone":{"value":{"size":"15px"}}}}}},"post":{"decoration":{"border":{"desktop":{"value":{"radius":{"sync":"on","topLeft":"12px","topRight":"12px","bottomRight":"12px","bottomLeft":"12px"}}}}},"advanced":{"number":{"desktop":{"value":"3"}},"categories":{"desktop":{"value":["all"]}},"offset":{"desktop":{"value":"0"}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Posts Grid"}}}},"builderVersion":"5.0.0-public-beta.8"} --><!-- /wp:divi/blog -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog FC CTA"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"80px","bottom":"80px","left":"24px","right":"24px","syncVertical":"off","syncHorizontal":"off"}}}},"background":{"desktop":{"value":{"color":"#000432","gradient":{"stops":[{"color":"#0f1419","position":0},{"color":"#000432","position":40},{"color":"#000864","position":100}],"direction":"135deg","enabled":true}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:linear-gradient(135deg,#0f1419 0%,#000432 40%,#000864 100%) !important}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"640px"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA Column"}}},"decoration":{}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"blog-fc-cta-inner\\">\\n  <h2>Managing Product Complexity?</h2>\\n  <p>Our team helps Thai manufacturers simplify their product data without losing visibility.</p>\\n  <a href=\\"/demo/\\" class=\\"blog-fc-cta-btn\\">\\n    <svg viewBox=\\"0 0 24 24\\" stroke-width=\\"2\\" aria-hidden=\\"true\\"><path d=\\"M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z\\"/></svg>\\n    Let\'s Talk\\n  </a>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Managing Product Complexity"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
