INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100811, '_et_pb_custom_css', '/* === MINIMAL STRUCTURAL RESET (vbNative — Divi modules handle all visual properties) === */\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden;margin:0}\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* ═══ Blog FC Hero (VB-Native) ═══ */\n\n/* Row + column sizing — JSON values not reliably rendered by Divi 5 beta,\n   so we enforce via CSS. JSON kept for VB Design panel display. */\n/* Original prototype: .blog-hero-inner { max-width: 1200px; padding: 0 24px; } */\n.et_pb_section_0 .et_pb_row.et_pb_row { max-width: 1200px !important; margin: 0 auto !important; }\n.et_pb_section_0 .et_pb_column.et_pb_column { padding: 0 24px !important; }\n\n/* Kill Divi default module spacing — we control margins precisely */\n.et_pb_section_0 .et_pb_module { margin-bottom: 0 !important; padding-bottom: 0 !important; }\n.et_pb_section_0 .et_pb_text .et_pb_text_inner p { padding-bottom: 0 !important; margin-bottom: 0 !important; }\n.et_pb_section_0 .et_pb_text .et_pb_text_inner h1 { padding-bottom: 0 !important; }\n.et_pb_section_0 .et_pb_code .et_pb_code_inner { padding: 0 !important; }\n\n/* Color overrides — Divi theme globals override JSON color on dark sections */\n.et_pb_section_0 .et_pb_text .et_pb_text_inner,\n.et_pb_section_0 .et_pb_text .et_pb_text_inner p,\n.et_pb_section_0 .et_pb_text .et_pb_text_inner h1 { color: #fff !important; }\n\n/* H1 title — original uses clamp(28px, 4.5vw, 42px) */\n.et_pb_section_0 .et_pb_text .et_pb_text_inner h1 {\n  font-size: clamp(28px, 4.5vw, 42px) !important;\n  font-weight: 700 !important;\n  line-height: 1.2 !important;\n  margin-bottom: 20px !important;\n}\n\n/* Back link + badge row */\n.blog-fc-nav-row {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  margin-bottom: 16px;\n}\n.blog-fc-back {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  color: rgba(255,255,255,0.85) !important;\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 15px;\n  font-weight: 500;\n  text-decoration: none;\n  transition: color 0.3s ease;\n}\n.blog-fc-back:hover { color: #00AFF0 !important; }\n.blog-fc-back svg { width: 16px; height: 16px; stroke: currentColor; }\n.blog-fc-badge {\n  display: inline-block;\n  font-family: \'JetBrains Mono\', monospace;\n  font-size: 11px;\n  font-weight: 500;\n  letter-spacing: 0.1em;\n  text-transform: uppercase;\n  color: #fff;\n  background: #00AFF0;\n  padding: 5px 12px;\n  border-radius: 4px;\n}\n\n/* Meta */\n.et_pb_section_0 .et_pb_text:last-child .et_pb_text_inner p {\n  color: rgba(255,255,255,0.85) !important;\n  font-size: 15px !important;\n}\n.blog-fc-meta-sep { margin: 0 6px; opacity: 0.5; }\n\n/* Dot pattern overlay — matches .blog-hero::before from styles.css */\n.et_pb_section_0::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n  background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n  pointer-events: none;\n  z-index: 1;\n}\n.et_pb_section_0.et_pb_section { position: relative; overflow: hidden; }\n\n/* Super D decoration */\n.blog-fc-super-d{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.06;pointer-events:none;z-index:0}\n\n/* Responsive — matching original prototype breakpoints */\n@media (max-width: 768px) {\n  .et_pb_section_0 .et_pb_text .et_pb_text_inner h1 { font-size: 26px !important; }\n  .blog-fc-back { min-height: 44px; padding: 8px 0; }\n}\n@media (max-width: 480px) {\n  .blog-fc-nav-row { flex-wrap: wrap; gap: 8px; }\n}\n\n/* Focus states */\n.et_pb_section_0 a:focus-visible { outline: 2px solid #00AFF0; outline-offset: 2px; border-radius: 2px; }\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .blog-fc-back { transition: none; }\n}\n/* ═══ Blog FC Content (VB-Native) ═══ */\n\n/* Row + column sizing — JSON maxWidth not reliably rendered by Divi 5 beta,\n   so we enforce via CSS. JSON kept for VB Design panel display. */\n.et_pb_section_1 .et_pb_row.et_pb_row { max-width: 760px !important; margin: 0 auto !important; padding-top: 0 !important; padding-bottom: 0 !important; }\n.et_pb_section_1 .et_pb_column.et_pb_column { padding: 0 24px !important; }\n\n/* Kill Divi default module spacing — we control margins precisely */\n.et_pb_section_1 .et_pb_module { margin-bottom: 0 !important; padding-bottom: 0 !important; }\n.et_pb_section_1 .et_pb_text .et_pb_text_inner p { padding-bottom: 0 !important; }\n.et_pb_section_1 .et_pb_text .et_pb_text_inner h2 { padding-bottom: 0 !important; }\n\n/* H2 spacing — matches .blog-body h2 { margin-top: 56px; margin-bottom: 20px; } */\n.et_pb_section_1 .et_pb_text_inner h2 {\n  margin: 56px 0 20px;\n  padding: 0;\n}\n/* First H2 in section doesn\'t need top margin (row spacing handles it) */\n.et_pb_section_1 .et_pb_row:first-child .et_pb_text_inner h2 { margin-top: 0; }\n\n/* Paragraph spacing — matches .blog-body p { font-size: 18px; margin-bottom: 24px; } */\n.et_pb_section_1 .et_pb_text_inner p {\n  font-size: 18px !important;\n  margin-bottom: 24px;\n  padding: 0;\n}\n.et_pb_section_1 .et_pb_text_inner p strong { color: #1a1a2e; }\n\n/* Links (Layer 3) */\n.et_pb_section_1 .et_pb_text a {\n  color: #00AFF0;\n  text-decoration: underline;\n  text-underline-offset: 2px;\n}\n\n/* Native list styling inside textModules — matches .blog-body ul { font-size: 18px; line-height: 1.8; } */\n.et_pb_section_1 .et_pb_text_inner ul {\n  list-style: none;\n  padding: 0;\n  margin: 16px 0 24px;\n  font-size: 18px;\n  line-height: 1.8;\n}\n.et_pb_section_1 .et_pb_text_inner li {\n  padding: 4px 0 4px 24px;\n  margin-bottom: 8px;\n  position: relative;\n}\n.et_pb_section_1 .et_pb_text_inner li::before {\n  content: \'\';\n  position: absolute;\n  left: 0; top: 14px;\n  width: 8px; height: 8px;\n  border-radius: 50%;\n  background: #00AFF0;\n}\n.et_pb_section_1 .et_pb_text_inner li strong { color: #000864; }\n\n/* Data card (Layer 4 — codeModule, complex layout) */\n.blog-fc-data-card {\n  background: #F5F7FA;\n  border-left: 4px solid #00AFF0;\n  border-radius: 0 12px 12px 0;\n  padding: 32px;\n  margin: 32px 0;\n  text-align: center;\n}\n.blog-fc-data-inline { display: flex; align-items: center; justify-content: center; gap: 24px; flex-wrap: wrap; }\n.blog-fc-data-number { font-family: \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 800; color: #000864; }\n.blog-fc-data-arrow { font-size: 32px; color: #00AFF0; font-weight: 700; }\n.blog-fc-data-label { font-family: \'JetBrains Mono\', monospace; font-size: 13px; font-weight: 500; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-top: 16px; }\n\n/* Highlight box (Layer 4 — codeModule, gradient bg) */\n.blog-fc-highlight {\n  background: linear-gradient(135deg, #f0f9ff, #e0f2fe);\n  border: 1px solid #bae6fd;\n  border-radius: 12px;\n  padding: 28px 32px;\n  margin: 32px 0;\n}\n.blog-fc-highlight p { font-family: \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.75; color: #333; margin: 0; padding: 0; }\n.blog-fc-highlight strong { color: #000864; }\n\n/* Responsive — matches .blog-body responsive rules from styles.css */\n@media (max-width: 768px) {\n  .et_pb_section_1 .et_pb_text_inner h2 { font-size: 24px !important; margin-top: 44px; }\n  .et_pb_section_1 .et_pb_text_inner p { font-size: 17px !important; }\n  .blog-fc-data-number { font-size: 28px; }\n}\n@media (max-width: 480px) {\n  .et_pb_section_1 .et_pb_text_inner p { font-size: 17px !important; line-height: 1.75 !important; }\n  .blog-fc-highlight { padding: 20px 24px; }\n  .blog-fc-data-inline { flex-direction: column; gap: 8px; }\n}\n\n/* Focus states */\n.et_pb_section_1 .et_pb_text a:focus-visible { outline: 2px solid #00AFF0; outline-offset: 2px; border-radius: 2px; }\n/* ═══ Blog FC FAQ (VB-Native Accordion) ═══ */\n\n/* Accordion card styling (Layer 3 — no native panel for border/radius on toggles) */\n.et_pb_section_2 .et_pb_toggle {\n  border: 1px solid #e5e7eb;\n  border-radius: 8px;\n  overflow: hidden;\n  margin-bottom: 12px;\n  background: #fff;\n}\n.et_pb_section_2 .et_pb_toggle_title {\n  padding: 16px 20px;\n}\n.et_pb_section_2 .et_pb_toggle_content {\n  padding: 0 20px 16px;\n}\n.et_pb_section_2 .et_pb_toggle_content p {\n  margin: 0;\n  padding: 0;\n}\n\n/* FAQ heading centering */\n.et_pb_section_2 .et_pb_text .et_pb_text_inner h2 {\n  text-align: center;\n  margin: 0;\n  padding: 0;\n}\n\n/* Accordion toggle icon — increase contrast (Layer 3) */\n.et_pb_section_2 .et_pb_toggle::before,\n.et_pb_section_2 .et_pb_toggle .et_pb_toggle_title::before { color: #666; }\n\n/* Focus states */\n.et_pb_section_2 .et_pb_toggle:focus-within { outline: 2px solid #00AFF0; outline-offset: 2px; }\n.et_pb_section_2 .et_pb_toggle_title:focus-visible { outline: 2px solid #00AFF0; outline-offset: 2px; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .et_pb_section_2 .et_pb_toggle_title { min-height: 44px; display: flex; align-items: center; }\n}\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .et_pb_section_2 .et_pb_toggle { transition: none; }\n}\n/* ═══ Blog FC Related (VB-Native Blog Module) ═══ */\n\n/* Blog module card styling (Layer 3 — Divi renders post HTML, needs CSS) */\n.et_pb_section_3 .et_pb_blog_grid .et_pb_post {\n  background: #fff;\n  border-radius: 12px;\n  overflow: hidden;\n  box-shadow: 0 2px 12px rgba(0,0,0,0.06);\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n}\n.et_pb_section_3 .et_pb_blog_grid .et_pb_post:hover {\n  transform: translateY(-4px);\n  box-shadow: 0 8px 24px rgba(0,0,0,0.1);\n}\n\n/* Heading centering */\n.et_pb_section_3 .et_pb_text .et_pb_text_inner h2 {\n  text-align: center;\n  margin: 0 0 48px;\n  padding: 0;\n}\n\n/* Hide pagination — not appropriate for "Related Articles" */\n.et_pb_section_3 .pagination { display: none; }\n\n/* Card excerpt — clean truncation */\n.et_pb_section_3 .et_pb_post .post-content p { display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }\n\n/* Focus states */\n.et_pb_section_3 .et_pb_post .entry-title a:focus-visible,\n.et_pb_section_3 .et_pb_post .more-link:focus-visible {\n  outline: 2px solid #00AFF0; outline-offset: 2px; border-radius: 2px;\n}\n\n/* Responsive */\n@media (max-width: 1024px) {\n  .et_pb_section_3 .et_pb_text .et_pb_text_inner h2 { font-size: 28px !important; }\n}\n@media (max-width: 768px) {\n  .et_pb_section_3 .et_pb_text .et_pb_text_inner h2 { font-size: 24px !important; margin-bottom: 32px !important; }\n  .et_pb_section_3 .et_pb_blog_grid { grid-template-columns: 1fr !important; }\n  .et_pb_section_3 .et_pb_post .more-link,\n  .et_pb_section_3 .et_pb_post .entry-categories a,\n  .et_pb_section_3 .et_pb_post .post-meta a { min-height: 44px; display: inline-flex; align-items: center; }\n}\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .et_pb_section_3 .et_pb_blog_grid .et_pb_post { transition: none; }\n  .et_pb_section_3 .et_pb_blog_grid .et_pb_post:hover { transform: none; }\n}\n/* ═══ Blog FC CTA (Matching Prototype) ═══ */\n\n/* Row + column sizing */\n.et_pb_section_4 .et_pb_row { max-width: 640px !important; margin: 0 auto !important; }\n.et_pb_section_4 .et_pb_module { margin-bottom: 0 !important; padding-bottom: 0 !important; }\n.et_pb_section_4 .et_pb_code .et_pb_code_inner { padding: 0 !important; }\n\n/* CTA inner layout */\n.blog-fc-cta-inner {\n  text-align: center;\n  position: relative;\n  z-index: 1;\n}\n.blog-fc-cta-inner h2 {\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: clamp(24px, 4vw, 36px);\n  font-weight: 700;\n  color: #fff;\n  margin: 0 0 16px;\n  line-height: 1.25;\n}\n.blog-fc-cta-inner p {\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 18px;\n  color: rgba(255,255,255,0.85);\n  line-height: 1.7;\n  margin: 0 0 32px;\n}\n\n/* Button — solid cyan with chat icon */\n.blog-fc-cta-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 10px;\n  background: #00AFF0;\n  color: #fff;\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 16px;\n  font-weight: 600;\n  padding: 16px 36px;\n  border-radius: 8px;\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n.blog-fc-cta-btn:hover {\n  background: #2b7bc4;\n  color: #fff;\n  transform: translateY(-2px);\n  box-shadow: 0 8px 24px rgba(0,175,240,0.3);\n}\n.blog-fc-cta-btn svg {\n  width: 18px;\n  height: 18px;\n  stroke: currentColor;\n  fill: none;\n}\n\n/* Dot-pattern overlay (matching prototype) */\n.et_pb_section_4::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n  background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n  pointer-events: none;\n}\n.et_pb_section_4.et_pb_section { position: relative; overflow: hidden; }\n\n/* Responsive */\n@media (max-width: 768px) {\n  .blog-fc-cta-inner h2 { font-size: 24px; }\n  .blog-fc-cta-btn { min-height: 48px; }\n}\n@media (max-width: 480px) {\n  .blog-fc-cta-btn { display: flex; justify-content: center; width: 100%; }\n}\n\n/* Focus states */\n.blog-fc-cta-btn:focus-visible { outline: 2px solid #fff; outline-offset: 4px; }\n\n/* Reduced motion */\n@media (prefers-reduced-motion: reduce) {\n  .blog-fc-cta-btn { transition: none; }\n  .blog-fc-cta-btn:hover { transform: none; }\n}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

-- Step 3: Ensure Divi 5 builder flags
DELETE FROM wp_postmeta WHERE post_id = 100811 AND meta_key = '_et_pb_use_builder';
