INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100811, '_et_pb_page_layout', 'et_full_width_page');

-- Step 4: Flush Divi cache
DELETE FROM wp_postmeta WHERE post_id = 100811 AND meta_key LIKE '_divi_dynamic_assets%';
